(async () => {
  const now = await api.getCurrentDatetime();
  const fromDate = new Date(now);
  fromDate.setDate(fromDate.getDate() - 7);
  const fromIso = fromDate.toISOString();
  const toIso = now;

  const allCustomers = await api.getAllCustomers({ limit: 1000, offset: 0 });
  let topCustomerId = null;
  let topCustomerName = null;
  let maxTransactions = 0;

  for (const cust of allCustomers) {
    const txns = await api.listTransactionsInWindow({
      fromIso,
      toIso,
      customerId: cust.id,
      limit: 1000
    });
    if (txns.length > maxTransactions) {
      maxTransactions = txns.length;
      topCustomerId = cust.id;
      topCustomerName = cust.name;
    }
  }

  if (topCustomerId) {
    const stats = await api.computeCustomerSpendStats({
      customerId: topCustomerId,
      fromIso,
      toIso
    });
    return {
      topCustomerId,
      topCustomerName,
      transactionCount: maxTransactions,
      totalSpend: stats.totalSpend,
      averageSpend: stats.averageSpend,
      fromIso,
      toIso
    };
  }
  return {
    topCustomerId: null,
    topCustomerName: null,
    transactionCount: 0,
    totalSpend: 0,
    averageSpend: 0,
    fromIso,
    toIso
  };
})();

